 33→const normalizeInteractionFlag = (value) => {
 34→    if(typeof value === 'boolean') return value;
 35→    if(typeof value === 'string'){
 36→        const normalized = value.trim().toLowerCase();
 37→        if(normalized === 'true') return true;
 38→        if(normalized === 'false') return false;
 39→    }
 40→    if(typeof value === 'number'){
 41→        return value === 1;
 42→    }
 43→    return Boolean(value);
 44→};
 45→
 46→const normalizeCount = (value) => {
 47→    const number = Number(value);
 48→    if(!Number.isFinite(number) || number < 0){
 49→        return 0;
 50→    }
 51→    return number;
 52→};
 53→
 54→const getNextToggleCount = (isActive, currentCount) => {
 55→    return isActive
 56→        ? Math.max(0, currentCount - 1)
 57→        : currentCount + 1;
 58→};
 59→
 60→const ContentView = () => {
 61→    const navigate = useNavigate();
 62→    const [showBackButton, setShowBackButton] = useState(true);
 63→    const { session, user, openAuthModal } = useAuth();
 64→
 65→    const timeOutRef = useRef();
 66→    const timeOutRefBookmark = useRef();
 67→    const likeInFlightRef = useRef(false);
 68→    const bookmarkInFlightRef = useRef(false);
 69→
 70→    const [showCommentsContainer, setShowCommentsContainer] = useState(false);
 71→    const [isLiked, setIsliked] = useState(false);
 72→    const [likesCount, setLikesCount] = useState(0);
 73→    const [userReaction, setUserReaction] = useState(null);
 74→    const [reactionCount, setReactionCount] = useState(0);
 75→    const [isBookmarked, setIsBookmarked] = useState(false);
 76→    const [bookmarkCounts, setBookmarkCounts] = useState(0);
 77→
 78→    const [bookmarkedMessage, setBookmarkedMessage] = useState('');
 79→    const [showRepostModal, setShowRepostModal] = useState(false);
 80→    const [showShareMenu, setShowShareMenu] = useState(false);
 81→
 82→    const contentRef = useRef();
 83→
 84→    const theme = {
 85→        paragraph: 'editor-paragraph',
 86→        heading: {
 87→            h1: 'editor-heading-h1',
 88→            h2: 'editor-heading-h2',
 89→            h3: 'editor-heading-h3',
 90→        },
 91→        quote: 'editor-quote',
 92→        text: {
 93→            bold: 'editor-text-bold',
 94→            italic: 'editor-text-italic',
 95→            underline: 'editor-text-underline',
 96→        }
 97→    }
 98→
 99→    const location = useLocation();
100→    const { journalId } = useParams();
101→    const statePostData = location.state;
102→    const shouldFetchPost = !!journalId && (!statePostData || !statePostData?.postType);
103→
104→    const { data: fetchedJournalData, isLoading: isLoadingJournalById } = useQuery({
105→        queryKey: ['journalById', journalId, user?.userData?.[0]?.id],
106→        queryFn: ({ queryKey }) => getJournalById(queryKey[1], queryKey[2]),
107→        enabled: shouldFetchPost,
108→        staleTime: 1000 * 60 * 5,
109→        refetchOnWindowFocus: false,
110→    });
111→
112→    const postData = useMemo(() => {
113→        const journal = fetchedJournalData?.journal;
114→        if(journal){
115→            const postType = journal?.post_type || 'text';
116→            const parsedContent = ParseContent(journal?.content);
117→            const wholeText = parsedContent?.wholeText || '';
118→
119→            return {
120→                postType: postType,
121→                content: journal?.content,
122→                wholeText: wholeText,
123→                title: journal?.title,
124→                userId: journal?.users?.id || journal?.user_id,
125→                name: journal?.users?.name,
126→                avatar: journal?.users?.image_url,
127→                created_at: journal?.created_at,
128→                journalId: journal?.id,
129→                isLiked: journal?.has_liked,
130→                commentsCount: journal?.comment_count?.[0]?.count || 0,
131→                isBookmarked: journal?.has_bookmarked,
132→                likesCount: journal?.like_count?.[0]?.count || 0,
133→                bookmarksCount: journal?.bookmark_count?.[0]?.count || 0,
134→                badge: journal?.users?.badge,
135→                isRepost: journal?.is_repost === true,
136→                repostCaption: journal?.repost_caption || '',
137→                repostSource: journal?.repost_source || null,
138→                userReaction: journal?.user_reaction || null,
139→                reactionCount: journal?.reaction_count?.[0]?.count || 0
140→            };
141→        }
142→
143→        if(!statePostData){
144→            return null;
145→        }
146→
147→        const inferredPostType = statePostData?.postType || 'text';
148→        const parsedContent = ParseContent(statePostData?.content);
149→
150→        return {
151→            postType: inferredPostType,
152→            content: statePostData?.content,
153→            wholeText: statePostData?.wholeText || parsedContent?.wholeText || '',
154→            title: statePostData?.title,
155→            userId: statePostData?.userId,
156→            name: statePostData?.name,
157→            avatar: statePostData?.avatar,
158→            created_at: statePostData?.created_at,
159→            journalId: statePostData?.journalId,
160→            isLiked: statePostData?.isLiked,
161→            commentsCount: statePostData?.commentsCount || 0,
162→            isBookmarked: statePostData?.isBookmarked,
163→            likesCount: statePostData?.likesCount || 0,
164→            bookmarksCount: statePostData?.bookmarksCount || 0,
165→            badge: statePostData?.badge,
166→            isRepost: statePostData?.isRepost === true,
167→            repostCaption: statePostData?.repostCaption || '',
168→            repostSource: statePostData?.repostSource || null,
169→            userReaction: statePostData?.userReaction || null,
170→            reactionCount: statePostData?.reactionCount || 0
171→        };
172→    }, [fetchedJournalData, statePostData]);
173→
174→    usePostSeo(postData);
175→
176→    const { data: followsData, isLoading: isLoadingFollows } = useQuery({
177→        queryKey: ['followsData', user?.userData?.[0]?.id, postData?.userId],
178→        queryFn: ({ queryKey }) => getFollowsData(queryKey[1], queryKey[2]),
179→        staleTime: 1000 * 60 * 60,
180→        cacheTime: 1000 * 60 * 60,
181→        enabled: !!user?.userData?.[0]?.id && !!postData?.userId,
182→    });
183→
184→    const handleclickUserProfile = handleClickProfile(navigate);
185→    const viewContent = handleCLickContent(navigate);
186→
187→    const mutateViews = useAddViewsMutation(session);
188→    const mutationLike = useLikeMutation(session, user?.userData?.[0]?.id);
189→    const mutationReaction = useReactionMutation(session, user?.userData?.[0]?.id);
190→
191→    const handleReaction = (e, journalId, receiverId, reactionType) => {
192→        e.stopPropagation();
193→        if (!session) { openAuthModal?.(); return; }
194→
195→        const wasReacted = userReaction;
196→        if (wasReacted === reactionType) {
197→            setUserReaction(null);
198→            setReactionCount((c) => Math.max(c - 1, 0));
199→        } else if (wasReacted) {
200→            setUserReaction(reactionType);
201→        } else {
202→            setUserReaction(reactionType);
203→            setReactionCount((c) => c + 1);
204→        }
205→        mutationReaction.mutate({ journalId, receiverId, reactionType });
206→    };
207→
208→    const handleClickLike = async (e, journalId, receiverId, senderImageUrl, sendername, senderEmail) => {
209→        e.stopPropagation();
210→        if(likeInFlightRef.current){
211→            return;
212→        }
213→        if(!session){
214→            openAuthModal?.();
215→            return;
216→        }
217→        const wasLiked = normalizeInteractionFlag(isLiked);
218→        likeInFlightRef.current = true;
219→        setIsliked(!wasLiked);
220→        setLikesCount((prevCount) => getNextToggleCount(wasLiked, normalizeCount(prevCount)));
221→        mutationLike.mutate(
222→            { journalId, receiverId, senderImageUrl, sendername, senderEmail },
223→            {
224→                onSettled: () => {
225→                    likeInFlightRef.current = false;
226→                }
227→            }
228→        );
229→    }
230→
231→    const mutationBookmark = useBookMarkMutation(session, user?.userData?.[0]?.id);
232→    const handleClickBookmark = async (e, journalId) => {
233→        e.stopPropagation();
234→        if(bookmarkInFlightRef.current){
235→            return;
236→        }
237→        if(!session){
238→            openAuthModal?.();
239→            return;
240→        }
241→        const wasBookmarked = normalizeInteractionFlag(isBookmarked);
242→        bookmarkInFlightRef.current = true;
243→        setIsBookmarked(!wasBookmarked);
244→        setBookmarkCounts((prevCount) => getNextToggleCount(wasBookmarked, normalizeCount(prevCount)));
245→        let response = null;
246→        try {
247→            response = await mutationBookmark.mutateAsync({ journalId });
248→        } finally {
249→            bookmarkInFlightRef.current = false;
250→        }
251→        
252→        if(timeOutRefBookmark.current){
253→            clearTimeout(timeOutRefBookmark.current);
254→        }
255→        if (response?.message === 'success') {
256→            setBookmarkedMessage('Post was added to your Bookmarks'); 
257→        } else if(response?.message === 'deleted'){
258→            setBookmarkedMessage('Post was removed from your Bookmarks');
259→        }
260→            
261→        timeOutRefBookmark.current = setTimeout(() => {
262→            setBookmarkedMessage('');
263→        }, 1500);
264→
265→    }
266→    const debounceClickBookmark = debounce(handleClickBookmark, 100);
267→
268→    const mutationFollow = useFollowMutation(session);
269→    const handleClickFollow = async (e, followingId, followerId) => {
270→        e.stopPropagation();
271→        if(!session) return openAuthModal();
272→        mutationFollow.mutate({ followingId, followerId });
273→    }
274→    const debounceClickFollow = debounce(handleClickFollow, 100);
275→
276→    const handleBackLocation = (e) => {
277→        e.stopPropagation();
278→        window.history.back();
279→    }
280→
281→    const hanldeClickComments = (e) => {
282→        e.stopPropagation();
283→        if(!session) return openAuthModal();
284→        setShowCommentsContainer(true);
285→    }
286→
287→    const handleCLoseComments = () => {
288→        setShowCommentsContainer(false);
289→    }
290→
291→    useEffect(() => {
292→        if (!postData) return;
293→        setLikesCount(normalizeCount(postData?.likesCount));
294→        setBookmarkCounts(normalizeCount(postData?.bookmarksCount));
295→        setIsliked(normalizeInteractionFlag(postData?.isLiked));
296→        setIsBookmarked(normalizeInteractionFlag(postData?.isBookmarked));
297→        setUserReaction(postData?.userReaction || null);
298→        setReactionCount(normalizeCount(postData?.reactionCount));
299→    }, [postData?.likesCount, postData?.bookmarksCount, postData?.isLiked, postData?.isBookmarked, postData?.userReaction, postData?.reactionCount]);
300→
301→    useEffect(() => {
302→        const hideBackBttn = () => {
303→            setShowBackButton(false);
304→            if (timeOutRef.current) {
305→                clearTimeout(timeOutRef.current);
306→            }
307→            timeOutRef.current = setTimeout(() => {
308→                setShowBackButton(true);
309→            }, 300);
310→        }
311→
312→        document.addEventListener('scroll', hideBackBttn, true);
313→        return () => {
314→            if (timeOutRef.current) {
315→                clearTimeout(timeOutRef.current);
316→            }
317→            document.removeEventListener('scroll', hideBackBttn, true);
318→        }
319→    }, []);
320→
321→    if (isLoadingJournalById || isLoadingFollows) {
322→        return (
323→            <div className="cv-loading">
324→                <MoonLoader loading={isLoadingJournalById || isLoadingFollows} color="var(--loader-color)" size={25} />
325→            </div>
326→        )
327→    }
328→
329→    if (!postData) {
330→        return (
331→            <div className="cv-loading">
332→                <p>Post is unavailable.</p>
333→                <button onClick={handleBackLocation} className="cv-back-btn" style={{ marginTop: "12px" }}>
334→                    Go back
