394→export const useReactionMutation = (session, userId) => {
395→    const queryClient = useQueryClient();
396→    const inFlightRef = useRef(new Set());
397→
398→    const mutation = useMutation({
399→        mutationFn: (data) => toggleReaction(session?.access_token, data),
400→
401→        onMutate: async (data) => {
402→            queryClient.cancelQueries({ queryKey: ['journals'] });
403→            queryClient.cancelQueries({ queryKey: ['userJournals'] });
404→            queryClient.cancelQueries({ queryKey: ['visitedProfileJournals'] });
405→
406→            const previousData = [
407→                ...queryClient.getQueriesData({ queryKey: ['journals'] }),
408→                ...queryClient.getQueriesData({ queryKey: ['userJournals'] }),
409→                ...queryClient.getQueriesData({ queryKey: ['visitedProfileJournals'] }),
410→            ];
411→
412→            const updater = (journal) => {
413→                if (journal.id !== data.journalId) return journal;
414→
415→                const currentReaction = journal?.user_reaction;
416→                const currentCount = normalizeCount(journal?.reaction_count?.[0]?.count);
417→
418→                let nextReaction;
419→                let nextCount;
420→
421→                if (currentReaction === data.reactionType) {
422→                    // Toggle off
423→                    nextReaction = null;
424→                    nextCount = Math.max(currentCount - 1, 0);
425→                } else if (currentReaction) {
426→                    // Switch reaction (count stays same)
427→                    nextReaction = data.reactionType;
428→                    nextCount = currentCount;
429→                } else {
430→                    // New reaction
431→                    nextReaction = data.reactionType;
432→                    nextCount = currentCount + 1;
433→                }
434→
435→                return {
436→                    ...journal,
437→                    user_reaction: nextReaction,
438→                    reaction_count: [{ count: nextCount }],
439→                };
440→            };
441→
442→            queryClient.setQueriesData({ queryKey: ['journals'] }, (old) => updateInfiniteJournalsCache(old, updater));
443→            queryClient.setQueriesData({ queryKey: ['userJournals'] }, (old) => updateInfiniteJournalsCache(old, updater));
444→            queryClient.setQueriesData({ queryKey: ['visitedProfileJournals'] }, (old) => updateInfiniteJournalsCache(old, updater));
445→
446→            return { previousData };
447→        },
448→
449→        onError: (err, data, context) => {
450→            context?.previousData?.forEach(([key, value]) => {
451→                queryClient.setQueryData(key, value);
452→            });
453→        },
454→
455→        onSettled: () => {
456→            queryClient.invalidateQueries({ queryKey: ['journals'] });
457→            queryClient.invalidateQueries({ queryKey: ['userJournals'] });
458→            queryClient.invalidateQueries({ queryKey: ['visitedProfileJournals'] });
459→            queryClient.invalidateQueries({ queryKey: ['postReactions'] });
460→        },
461→    });
462→
463→    const guardedMutate = (variables, options) => {
464→        const journalKey = toJournalKey(variables?.journalId);
465→        if (journalKey && inFlightRef.current.has(journalKey)) return;
466→
467→        if (journalKey) inFlightRef.current.add(journalKey);
468→
469→        mutation.mutate(variables, {
470→            ...options,
471→            onSettled: (data, error, vars, context) => {
472→                if (journalKey) inFlightRef.current.delete(journalKey);
473→                options?.onSettled?.(data, error, vars, context);
474→            },
475→        });
476→    };
477→
478→    return { ...mutation, mutate: guardedMutate };
479→}
