  73→const optionalAuth = async (req, _res, next) => {
  74→    const token = extractBearerToken(req.headers?.authorization);
  75→    if (!token) {
  76→        return next();
  77→    }
  78→
  79→    const { user } = await resolveAuthUser(token);
  80→    if (user?.id) {
  81→        req.userId = user.id;
  82→        req.authUser = user;
  83→    }
  84→
  85→    return next();
