        const response = await apiRequest(url, {
            method: 'GET',
            headers: headers
        })

        if(!response.ok){
            throw new Error('failed to get response');
        }
        const data = await response.json();
        // console.log(data);
        return data
    } catch (error) {
        console.error('Error fetching user journals:', error);
        throw error;
    }
}

